
const parts= (fileName: string) => {
    const cleanName = fileName.split('?')[0]?.split('#')[0]; // handle URLs
    const lastDotIndex = cleanName?.lastIndexOf('.');

    // No extension or hidden file like ".env"
    if (lastDotIndex && lastDotIndex <= 0) {
        return {
            name: cleanName ?? '',
            ext: ''
        };
    }

    return {
        name: cleanName?.slice(0, lastDotIndex) ?? '',
        ext: cleanName?.slice((lastDotIndex ?? 0) + 1).toLowerCase() ?? ''
    };
}

const ext= (fileName: string) => {
    const lastDotIndex = fileName.lastIndexOf('.');
    if (lastDotIndex === -1 || lastDotIndex === 0) return '';

    return fileName.slice(lastDotIndex + 1).toLowerCase();
}

const shortName = (
    fileName: string,
    startLength: number = 15,
    endLength: number = 5
) => {
    const lastDotIndex = fileName.lastIndexOf('.');
    if (lastDotIndex === -1) return fileName;

    const name = fileName.slice(0, lastDotIndex);
    const ext = fileName.slice(lastDotIndex);

    if (name.length <= startLength + endLength) {
        return fileName;
    }

    const start = name.slice(0, startLength);
    const end = name.slice(-endLength);

    return `${start}....${end}${ext}`;
};



export const AnyFile = {parts, ext, shortName}
